import Vue from 'vue'
import App from './App.vue'
import router from './router'
import Carousel3d from 'vue-carousel-3d';
Vue.use(Carousel3d);
Vue.config.productionTip = false
Vue.directive('scroll', {
  inserted: function (el, binding) {
    let f = function (evt) {
      if (binding.value(evt, el)) {
        document.querySelector(".modal").removeEventListener('scroll', f)
      }
    }
    document.querySelector(".modal").addEventListener('scroll', f)
  }
})
new Vue({
  router,
  render: h => h(App)
}).$mount('#app')
